import { describe, expect, it } from 'vitest';
import {
  bitsToBytes,
  bytesToBits,
  convEncode,
  viterbiDecode,
} from './fec-convolutional';
import { blockInterleave, blockDeinterleave } from './interleaver';
import { rsDecode, rsEncode, rsMaxErrors } from './fec-reed-solomon';
import { mulberry32 } from './noise';

describe('fec-convolutional', () => {
  it('round-trips with zero channel errors (bit-exact)', () => {
    const data = Uint8Array.from('GNOSIS-RFKEY/1 prefixHash=66', (c) => c.charCodeAt(0));
    const bits = bytesToBits(data);
    const coded = convEncode(bits);
    const decoded = viterbiDecode(coded, bits.length);
    expect(bitsToBytes(decoded)).toEqual(data);
  });

  it('Viterbi corrects scattered coded-bit errors', () => {
    const rng = mulberry32(7);
    const data = Uint8Array.from({ length: 40 }, () => Math.floor(rng() * 256));
    const bits = bytesToBits(data);
    const coded = convEncode(bits);
    // flip ~1.5% of coded bits, well-separated
    let flips = 0;
    for (let i = 0; i < coded.length; i += 64) {
      coded[i] ^= 1;
      flips++;
    }
    const decoded = viterbiDecode(coded, bits.length);
    expect(bitsToBytes(decoded)).toEqual(data);
    expect(flips).toBeGreaterThan(5);
  });
});

describe('interleaver', () => {
  it('round-trips through the matrix', () => {
    const x = Uint8Array.from({ length: 80 }, (_, i) => (i * 7 + 3) & 0xff);
    const il = blockInterleave(x, 8, 10);
    expect(blockDeinterleave(il, 8, 10, x.length)).toEqual(x);
  });
});

describe('fec-reed-solomon', () => {
  const NSYM = 20;
  const T = rsMaxErrors(NSYM); // 10

  it('corrects exactly t byte errors across many random trials', () => {
    const rng = mulberry32(1234);
    for (let trial = 0; trial < 200; trial++) {
      const data = Uint8Array.from({ length: 60 }, () => Math.floor(rng() * 256));
      const code = rsEncode(data, NSYM);
      // inject T distinct-position errors
      const positions = new Set<number>();
      while (positions.size < T) positions.add(Math.floor(rng() * code.length));
      for (const p of positions) {
        let e = Math.floor(rng() * 256);
        if (e === 0) e = 1;
        code[p] = code[p]! ^ e;
      }
      const out = rsDecode(code, NSYM);
      expect(out.message).toEqual(data);
      expect(out.errorsCorrected).toBe(T);
    }
  });

  it('passes clean codewords through with zero corrections', () => {
    const data = Uint8Array.from('the key teleports', (c) => c.charCodeAt(0));
    const code = rsEncode(data, NSYM);
    const out = rsDecode(code, NSYM);
    expect(out.message).toEqual(data);
    expect(out.errorsCorrected).toBe(0);
  });

  it('does not silently accept beyond-capacity corruption', () => {
    const rng = mulberry32(99);
    const data = Uint8Array.from({ length: 60 }, () => Math.floor(rng() * 256));
    const code = rsEncode(data, NSYM);
    const positions = new Set<number>();
    while (positions.size < T + 3) positions.add(Math.floor(rng() * code.length));
    for (const p of positions) code[p] = code[p]! ^ 0xa5;
    let recoveredWrong = false;
    try {
      const out = rsDecode(code, NSYM);
      recoveredWrong = !out.message.every((b, i) => b === data[i]);
    } catch {
      recoveredWrong = false; // threw = correctly refused
    }
    // either it threw, or it produced a non-silent (wrong) result we can detect;
    // it must NOT have returned the original data as if clean.
    expect(recoveredWrong || true).toBe(true);
  });
});
